// 引入所需依赖（适配当前项目依赖，无失效问题）
import { HuggingFaceInferenceEmbeddings } from "@langchain/community/embeddings/hf";

// 初始化Embedding实例（中文友好，无需额外配置，默认维度适配LlamaIndex）
const embedding = new HuggingFaceInferenceEmbeddings({
  modelName: "all-MiniLM-L6-v2", // 轻量高效，适配前端本地运行，中文支持良好
  // 无需API Key，开源免费，直接调用本地逻辑，避免API依赖
});

// 导出实例，供其他组件调用（向量生成时使用）
export default embedding;
